namespace NotificationApp.Services;

public enum Severity
{
    Info,
    Warning,
    Critical
}

public class NotificationItem
{
    public Guid Id { get; init; } = Guid.NewGuid();
    public required string Title { get; init; }
    public required string Message { get; init; }
    public Severity Severity { get; init; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; init; } = DateTime.UtcNow;
}

public class NotificationHub
{
    private readonly List<NotificationItem> _notifications = [];
    private readonly object _lock = new();

    public event Action? OnChange;

    public IReadOnlyList<NotificationItem> Notifications
    {
        get { lock (_lock) { return _notifications.ToList(); } }
    }

    public int GetUnreadCount()
    {
        lock (_lock) { return _notifications.Count(n => !n.IsRead); }
    }

    public void AddNotification(string title, string message, Severity severity)
    {
        lock (_lock)
        {
            _notifications.Insert(0, new NotificationItem
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }
        OnChange?.Invoke();
    }

    public void MarkAsRead(Guid id)
    {
        lock (_lock)
        {
            var item = _notifications.FirstOrDefault(n => n.Id == id);
            if (item is not null) item.IsRead = true;
        }
        OnChange?.Invoke();
    }

    public void MarkAllRead()
    {
        lock (_lock)
        {
            foreach (var item in _notifications) item.IsRead = true;
        }
        OnChange?.Invoke();
    }

    public void DismissNotification(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }
        OnChange?.Invoke();
    }
}

namespace NotificationApp.Services;

public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private Timer? _timer;
    private static readonly string[] Titles =
    [
        "Server CPU spike", "Deployment completed", "Disk usage warning",
        "New user registered", "Payment failed", "Certificate expiring",
        "Backup succeeded", "API rate limit hit", "Memory threshold exceeded"
    ];
    private static readonly string[] Messages =
    [
        "Check monitoring dashboard for details.",
        "Review the latest logs for more information.",
        "Immediate attention may be required.",
        "This is an automated system notification.",
        "No action needed — informational only."
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        _timer ??= new Timer(_ =>
        {
            var rng = Random.Shared;
            var title = Titles[rng.Next(Titles.Length)];
            var message = Messages[rng.Next(Messages.Length)];
            var severity = (Severity)rng.Next(3);
            _hub.AddNotification(title, message, severity);
        }, null, TimeSpan.FromSeconds(15), TimeSpan.FromSeconds(15));
    }

    public void Dispose()
    {
        _timer?.Dispose();
        _timer = null;
    }
}

