namespace NotificationApp.Services;

public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private Timer? _timer;
    private static readonly string[] Titles =
    [
        "Server CPU spike", "Deployment completed", "Disk usage warning",
        "New user registered", "Payment failed", "Certificate expiring",
        "Backup succeeded", "API rate limit hit", "Memory threshold exceeded"
    ];
    private static readonly string[] Messages =
    [
        "Check monitoring dashboard for details.",
        "Review the latest logs for more information.",
        "Immediate attention may be required.",
        "This is an automated system notification.",
        "No action needed — informational only."
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        _timer ??= new Timer(_ =>
        {
            var rng = Random.Shared;
            var title = Titles[rng.Next(Titles.Length)];
            var message = Messages[rng.Next(Messages.Length)];
            var severity = (Severity)rng.Next(3);
            _hub.AddNotification(title, message, severity);
        }, null, TimeSpan.FromSeconds(15), TimeSpan.FromSeconds(15));
    }

    public void Dispose()
    {
        _timer?.Dispose();
        _timer = null;
    }
}

