@using NotificationApp.Services
@rendermode InteractiveServer
@inject NotificationHub Hub
@implements IDisposable

<div class="notification-bell" @onclick="Toggle">
    🔔
    @if (_unreadCount > 0)
    {
        <span class="badge">@_unreadCount</span>
    }
</div>

@code {
    private int _unreadCount;
    private Action? _handler;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        _handler = () => InvokeAsync(() =>
        {
            _unreadCount = Hub.GetUnreadCount();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    private void Toggle()
    {
        // Could open a dropdown; for now just navigates
    }

    public void Dispose()
    {
        Hub.OnChange -= _handler;
    }
}

.notification-bell {
    position: relative;
    display: inline-block;
    cursor: pointer;
    font-size: 1.5rem;
    padding: 0.25rem 0.5rem;
}

.notification-bell .badge {
    position: absolute;
    top: -4px;
    right: -4px;
    background: #dc3545;
    color: white;
    border-radius: 50%;
    font-size: 0.7rem;
    min-width: 18px;
    height: 18px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
}

