arguments.file_text:
@page "/notifications"
@rendermode InteractiveServer
@using NotificationApp.Services
@inject NotificationHub Hub
@implements IDisposable

<h1>Notifications</h1>

<button class="btn btn-secondary" @onclick="Hub.MarkAllRead">Mark All Read</button>

@foreach (var group in GetGrouped())
{
    <h2 class="severity-header severity-@group.Key.ToString().ToLower()">@group.Key</h2>
    @foreach (var item in group.Items)
    {
        <div class="notification-card @(item.IsRead ? "read" : "unread")">
            <div class="notification-content">
                <strong>@item.Title</strong>
                <p>@item.Message</p>
                <small>@item.Timestamp.ToString("g")</small>
            </div>
            <div class="notification-actions">
                @if (!item.IsRead)
                {
                    <button class="btn btn-sm" @onclick="() => Hub.MarkAsRead(item.Id)">Mark Read</button>
                }
                <button class="btn btn-sm btn-danger" @onclick="() => Hub.DismissNotification(item.Id)">Dismiss</button>
            </div>
        </div>
    }
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        Hub.OnChange += _handler;
    }

    private List<(Severity Key, List<NotificationItem> Items)> GetGrouped()
    {
        return Hub.Notifications
            .GroupBy(n => n.Severity)
            .OrderByDescending(g => g.Key)
            .Select(g => (g.Key, g.ToList()))
            .ToList();
    }

    public void Dispose()
    {
        Hub.OnChange -= _handler;
    }
}

.severity-header {
    margin-top: 1.5rem;
    padding: 0.25rem 0.5rem;
    border-radius: 4px;
}

.severity-critical { color: #dc3545; }
.severity-warning { color: #ffc107; }
.severity-info { color: #0dcaf0; }

.notification-card {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    margin-bottom: 0.5rem;
    border: 1px solid #dee2e6;
    border-radius: 6px;
}

.notification-card.unread {
    background: #f0f7ff;
    border-left: 4px solid #0d6efd;
}

.notification-card.read {
    opacity: 0.7;
}

.notification-actions {
    display: flex;
    gap: 0.5rem;
}

.btn {
    cursor: pointer;
    padding: 0.375rem 0.75rem;
    border: 1px solid #6c757d;
    border-radius: 4px;
    background: white;
}

.btn-danger {
    background: #dc3545;
    color: white;
    border-color: #dc3545;
}

.btn-secondary {
    background: #6c757d;
    color: white;
    border-color: #6c757d;
}

.btn-sm {
    padding: 0.2rem 0.5rem;
    font-size: 0.85rem;
}

@page "/dashboard"
@rendermode InteractiveServer
@using NotificationApp.Services
@inject NotificationHub Hub
@inject SimulatorService Simulator
@implements IDisposable

<h1>Dashboard</h1>

<NotificationSummaryPanel />

<p style="margin-top:2rem; color:#6c757d;">
    A random notification is added every 15 seconds to simulate server-push events.
</p>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        Simulator.Start();
        _handler = () => InvokeAsync(StateHasChanged);
        Hub.OnChange += _handler;
    }

    public void Dispose()
    {
        Hub.OnChange -= _handler;
        Simulator.Dispose();
    }
}

@using NotificationApp.Services
@inject NotificationHub Hub
@implements IDisposable

<div class="summary-panel">
    <h3>Recent Unread</h3>
    @if (!_recent.Any())
    {
        <p class="empty">No unread notifications.</p>
    }
    else
    {
        @foreach (var item in _recent)
        {
            <div class="summary-item">
                <span class="severity-dot severity-@item.Severity.ToString().ToLower()"></span>
                <div class="summary-text">
                    <strong>@item.Title</strong>
                    <small>@item.Message</small>
                </div>
                <button class="btn btn-sm" @onclick="() => Hub.DismissNotification(item.Id)">✕</button>
            </div>
        }
    }
</div>

@code {
    private List<NotificationItem> _recent = [];
    private Action? _handler;

    protected override void OnInitialized()
    {
        UpdateRecent();
        _handler = () => InvokeAsync(() =>
        {
            UpdateRecent();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    private void UpdateRecent()
    {
        _recent = Hub.Notifications
            .Where(n => !n.IsRead)
            .Take(3)
            .ToList();
    }

    public void Dispose()
    {
        Hub.OnChange -= _handler;
    }
}

.summary-panel {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1rem;
    max-width: 500px;
}

.summary-panel h3 {
    margin-top: 0;
}

.empty {
    color: #6c757d;
    font-style: italic;
}

.summary-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.5rem 0;
    border-bottom: 1px solid #f0f0f0;
}

.summary-item:last-child {
    border-bottom: none;
}

.severity-dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    flex-shrink: 0;
}

.severity-dot.severity-critical { background: #dc3545; }
.severity-dot.severity-warning { background: #ffc107; }
.severity-dot.severity-info { background: #0dcaf0; }

.summary-text {
    flex: 1;
    display: flex;
    flex-direction: column;
}

.summary-text small {
    color: #6c757d;
}

