toolArgs.file_text:
.summary-panel {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1rem;
    max-width: 500px;
}

.summary-panel h3 {
    margin-top: 0;
}

.empty {
    color: #6c757d;
    font-style: italic;
}

.summary-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.5rem 0;
    border-bottom: 1px solid #f0f0f0;
}

.summary-item:last-child {
    border-bottom: none;
}

.severity-dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    flex-shrink: 0;
}

.severity-dot.severity-critical { background: #dc3545; }
.severity-dot.severity-warning { background: #ffc107; }
.severity-dot.severity-info { background: #0dcaf0; }

.summary-text {
    flex: 1;
    display: flex;
    flex-direction: column;
}

.summary-text small {
    color: #6c757d;
}

